"use client";

import { Tabs as TabsPrimitive } from "@base-ui/react/tabs";

import { cx, x } from "@/lib/utils";

import { styles } from "./tabs.stylex";

const Tabs = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof TabsPrimitive.Root>, "className"> & {
  className?: string;
}) => {
  const p = x(styles.root);
  return (
    <TabsPrimitive.Root
      data-slot="tabs"
      className={cx(p.className, className)}
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const TabsList = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof TabsPrimitive.List>, "className"> & {
  className?: string;
}) => {
  const p = x(styles.list);
  return (
    <TabsPrimitive.List
      data-slot="tabs-list"
      className={cx(p.className, className)}
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const TabsTrigger = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof TabsPrimitive.Tab>, "className"> & {
  className?: string;
}) => (
  <TabsPrimitive.Tab
    data-slot="tabs-trigger"
    className={(state) =>
      cx(
        x(styles.trigger, state.active && styles.triggerActive).className,
        className
      )
    }
    style={style}
    {...props}
  />
);

const TabsContent = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof TabsPrimitive.Panel>, "className"> & {
  className?: string;
}) => {
  const p = x(styles.panel);
  return (
    <TabsPrimitive.Panel
      data-slot="tabs-content"
      className={cx(p.className, className)}
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

export { Tabs, TabsContent, TabsList, TabsTrigger };

import * as stylex from "@stylexjs/stylex";

import { colors, radius } from "../tokens.stylex";

export const styles = stylex.create({
  list: {
    alignItems: "center",
    backgroundColor: colors.muted,
    borderRadius: "0.5rem",
    color: colors.mutedForeground,
    display: "inline-flex",
    height: "2.25rem",
    justifyContent: "center",
    padding: "0.25rem",
    width: "fit-content",
  },
  panel: {
    flex: 1,
    outline: "none",
  },
  root: {
    display: "flex",
    flexDirection: "column",
    gap: "0.5rem",
  },
  trigger: {
    alignItems: "center",
    background: "transparent",
    borderColor: "transparent",
    borderRadius: radius.md,
    borderStyle: "solid",
    borderWidth: "1px",
    boxShadow: {
      ":focus-visible": `0 0 0 3px color-mix(in oklab, ${colors.ring} 50%, transparent)`,
      default: null,
    },
    color: colors.foreground,
    cursor: "pointer",
    display: "inline-flex",
    flex: 1,
    fontSize: "0.875rem",
    fontWeight: 500,
    gap: "0.375rem",
    justifyContent: "center",
    outline: "none",
    paddingBlock: "0.25rem",
    paddingInline: "0.75rem",
    transition: "color 0.15s ease-in-out, box-shadow 0.15s ease-in-out",
    whiteSpace: "nowrap",
  },
  triggerActive: {
    backgroundColor: colors.background,
    boxShadow: "0 1px 2px 0 rgb(0 0 0 / 0.05)",
    color: colors.foreground,
  },
});
